-- 2026-06-25: shoulder_tsa — фазы «Путь» + структурированные критерии перехода.
-- Протокол: анатомическое тотальное эндопротезирование плечевого сустава (aTSA).
--
-- Источник: PROTOCOLS/shoulder/shoulder_tsa*.md + _extractions_newbatch.json
-- (объект suggested_program_type_code='shoulder_tsa', 5 фаз 0..4, anchor time_and_criterion).
-- Целиком послеоперационный: фаза 0 (prehab) — ДО операции; фазы 1–4 — после.
-- Прогрессия time_and_criterion: недели — нижний ориентир, переход внутри окна по объёму
-- движений / боли / клиническим критериям (не по календарю).
--
-- Защитная ось TSA: бережём шов ПОДЛОПАТОЧНОЙ мышцы → ранний запрет поворота руки наружу
-- за нейтраль и активного/силового поворота внутрь; запрет осевой опоры и заведения руки за
-- спину. (Зеркально RSA, где бережём дельтовидную + анти-вывиховые предосторожности.)
--
-- Контент в ПАЦИЕНТСКОМ регистре (без жаргона PROM/ER/IR/MMT — раскрыт словами: «пассивный
-- подъём руки вперёд», «поворот руки наружу/внутрь», «подлопаточная мышца»). Vadim калибрует
-- через AdminContent после деплоя.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их сразу
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев: авто-проверяемо сегодня только боль ВАШ → 'measurement'
-- (measurement_type='vas_score', source='pain'). У TSA болевых ВАШ-порогов в источнике нет → все
-- критерии 'instructor_check' (числа по объёму движений — в ТЕКСТЕ label, куратор вводит очно)
-- либо 'self_report' (качественное да/нет). Фаза 0 (prehab) и фаза 4 (терминальная, без критериев
-- в источнике) — без structured-критериев (criteria_next текстом).
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц. НЕ трогает другие program_type.

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_tsa (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
