ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_tsa
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) и фаза 4 (терминальная, без критериев в источнике) — не в WITH.
--    У TSA нет болевых ВАШ-порогов → measurement-критериев нет; всё instructor_check/self_report.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (покой и защита → восстановление активных движений)
  (1, 'passive_flexion_90',   'Пассивный подъём руки вперёд не менее 90° (примерно половина от здоровой стороны), без боли',          'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_30',        'Пассивный поворот руки наружу в плоскости лопатки до 30°, без боли и без признаков перегрузки шва',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'passive_ir_70',        'Пассивный поворот руки внутрь в плоскости лопатки не менее 70°',                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'pain_decreasing_p1',   'Боль стихает от недели к неделе, пассивные упражнения переносятся без резкой боли',                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Стихает ли боль от недели к неделе и переносите ли вы пассивные упражнения без резкой боли?', 'Сравните самочувствие с прошлой неделей', 40::smallint, TRUE),
  (1, 'healing_ok_p1',        'Мышцы вокруг лопатки включаются, нет признаков проблем со швом подлопаточной или инфекции (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление активных движений → умеренное укрепление)
  (2, 'active_flexion_120',   'Активный подъём руки вперёд не менее 120°',                                                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_abduction_100', 'Активное отведение руки в сторону не менее 100°',                                                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'active_er_45',         'Поворот руки наружу не менее 45° без боли (единого порога нет — ориентир; решает куратор очно)',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'active_mechanics_p2',  'Активный подъём руки против силы тяжести с правильной механикой, без лишних компенсаций (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (2, 'active_painfree_p2',   'Получается двигать рукой активно без острой боли',                                                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается двигать рукой активно без острой боли?', 'Оцените по нескольким активным движениям', 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (умеренное укрепление → возврат к активности)
  (3, 'active_flexion_140',   'Активный подъём руки вперёд не менее 140°',                                                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'active_abduction_120', 'Активное отведение руки не менее 120°',                                                                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'er_60_p3',             'Поворот руки наружу в плоскости лопатки не менее 60°',                                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'ir_70_p3',             'Поворот руки внутрь в плоскости лопатки не менее 70°',                                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'resistance_ok_p3',     'Симметричная работа лопатки и переносимость силовой нагрузки без усиления боли (оценка куратора)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  (3, 'adl_painfree_p3',      'Бытовые дела оперированной рукой даются без значимой боли',                                            'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Справляетесь с бытовыми делами оперированной рукой без значимой боли?', 'Например, одеться, поесть, дотянуться до полки', 60::smallint, TRUE),
  (3, 'surgeon_clear_p3',     'Разрешение хирурга на продвинутое укрепление и возврат к активности (решает куратор/хирург очно)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 70::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_tsa' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
